import{_ as e,o as a,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"GPU集群从芯片到电网的全链路瓶颈拆解","description":"当1瓦GPU功耗变成2.44瓦的电表读数，哪一层最先断？变压器→电网并网→液冷搁浅→芯片约束，四层瓶颈优先级排序","frontmatter":{"title":"GPU集群从芯片到电网的全链路瓶颈拆解","description":"当1瓦GPU功耗变成2.44瓦的电表读数，哪一层最先断？变压器→电网并网→液冷搁浅→芯片约束，四层瓶颈优先级排序"},"headers":[],"relativePath":"算电协同/GPU集群全链路瓶颈拆解.md","filePath":"算电协同/GPU集群全链路瓶颈拆解.md","lastUpdated":1781978464000}'),n={name:"算电协同/GPU集群全链路瓶颈拆解.md"};function i(d,t,o,s,h,g){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="gpu集群从芯片到电网的全链路瓶颈拆解" tabindex="-1">GPU集群从芯片到电网的全链路瓶颈拆解 <a class="header-anchor" href="#gpu集群从芯片到电网的全链路瓶颈拆解" aria-label="Permalink to &quot;GPU集群从芯片到电网的全链路瓶颈拆解&quot;">​</a></h1><h2 id="当1瓦gpu功耗变成2-44瓦的电表读数-哪一层最先断" tabindex="-1">当1瓦GPU功耗变成2.44瓦的电表读数，哪一层最先断？ <a class="header-anchor" href="#当1瓦gpu功耗变成2-44瓦的电表读数-哪一层最先断" aria-label="Permalink to &quot;当1瓦GPU功耗变成2.44瓦的电表读数，哪一层最先断？&quot;">​</a></h2><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>AI基础设施投资的核心矛盾正在发生根本性转变。从GPU芯片功耗指数级增长（400W→2,300W，五年5.75倍）出发，沿机柜散热（40kW/柜→600kW/柜）、数据中心配电（变压器供给缺口30%+、交付周期160周）、到区域电网并网（PJM排队5年+、ERCOT收到250GW申报容量）逐一拆解。结论：变压器是当前最短的木板，区域电网并网是最慢的瓶颈，液冷基础设施的存量搁浅是2027-2028年的灰犀牛——而芯片供应反而是约束最少的环节。</p><hr><h2 id="一、引言-一个被忽视的乘法效应" tabindex="-1">一、引言：一个被忽视的乘法效应 <a class="header-anchor" href="#一、引言-一个被忽视的乘法效应" aria-label="Permalink to &quot;一、引言：一个被忽视的乘法效应&quot;">​</a></h2><p>讨论AI数据中心功耗时，大多数人只看GPU的TDP。但这个视角忽略了整个电力链路的累加放大效应。</p><p>Epoch AI对GB200 NVL72系统的全链路功耗建模揭示了一个关键数字：<strong>1瓦GPU功耗，到电表上变成2.44瓦。</strong> 放大过程如下：</p><table tabindex="0"><thead><tr><th style="text-align:center;">层级</th><th style="text-align:center;">放大系数</th><th>说明</th></tr></thead><tbody><tr><td style="text-align:center;">服务器级</td><td style="text-align:center;">×1.53</td><td>CPU、内存、NVSwitch、网卡、风扇、电源转换损耗</td></tr><tr><td style="text-align:center;">共享IT设备</td><td style="text-align:center;">×1.14</td><td>网络交换机、管理服务器、存储系统</td></tr><tr><td style="text-align:center;">设施配套</td><td style="text-align:center;">×1.40</td><td>冷却系统、配电损耗、照明</td></tr><tr><td style="text-align:center;"><strong>合计</strong></td><td style="text-align:center;"><strong>×2.44</strong></td><td>每1W GPU → 2.44W电表读数</td></tr></tbody></table><p>含义：一个Rubin机柜（190kW GPU功耗）实际需要的配电容量接近470kW。一个标称500MW的AI数据中心园区，到电网取电时实际需要1.22GW。链路上的每一层放大都在叠加，而每一层都有自己的瓶颈。</p><hr><h2 id="二、芯片级-功耗暴涨的物理逻辑" tabindex="-1">二、芯片级：功耗暴涨的物理逻辑 <a class="header-anchor" href="#二、芯片级-功耗暴涨的物理逻辑" aria-label="Permalink to &quot;二、芯片级：功耗暴涨的物理逻辑&quot;">​</a></h2><h3 id="_2-1-跨代功耗数据" tabindex="-1">2.1 跨代功耗数据 <a class="header-anchor" href="#_2-1-跨代功耗数据" aria-label="Permalink to &quot;2.1 跨代功耗数据&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">芯片</th><th style="text-align:center;">发布年</th><th style="text-align:center;">TDP</th><th style="text-align:center;">单机柜功耗</th><th style="text-align:center;">制程</th></tr></thead><tbody><tr><td style="text-align:center;">A100</td><td style="text-align:center;">2020</td><td style="text-align:center;">400W</td><td style="text-align:center;">15-20kW</td><td style="text-align:center;">7nm</td></tr><tr><td style="text-align:center;">H100</td><td style="text-align:center;">2022</td><td style="text-align:center;">700W</td><td style="text-align:center;">30-40kW</td><td style="text-align:center;">4nm</td></tr><tr><td style="text-align:center;">B200</td><td style="text-align:center;">2024</td><td style="text-align:center;">1,000W（风冷）/ 1,200W（液冷）</td><td style="text-align:center;">120-130kW</td><td style="text-align:center;">4nm定制</td></tr><tr><td style="text-align:center;">B300</td><td style="text-align:center;">2025</td><td style="text-align:center;">1,400W</td><td style="text-align:center;">~140kW</td><td style="text-align:center;">4nm定制</td></tr><tr><td style="text-align:center;">Vera Rubin R100</td><td style="text-align:center;">2026 H2</td><td style="text-align:center;">2,300W</td><td style="text-align:center;">190-230kW</td><td style="text-align:center;">3nm</td></tr><tr><td style="text-align:center;">Kyber Ultra NVL576</td><td style="text-align:center;">2027</td><td style="text-align:center;">—</td><td style="text-align:center;">~600kW</td><td style="text-align:center;">3nm</td></tr><tr><td style="text-align:center;">Feynman</td><td style="text-align:center;">2028+</td><td style="text-align:center;">—</td><td style="text-align:center;">1MW级</td><td style="text-align:center;">下一代</td></tr></tbody></table><p>单芯片TDP五年增长5.75倍（400W→2,300W）。单机柜功耗五年增长30倍（20kW→600kW）。</p><h3 id="_2-2-功耗增长的物理根源" tabindex="-1">2.2 功耗增长的物理根源 <a class="header-anchor" href="#_2-2-功耗增长的物理根源" aria-label="Permalink to &quot;2.2 功耗增长的物理根源&quot;">​</a></h3><p>GPU功耗暴涨不是设计缺陷——是Demand scaling失效后的必然结果。自2006年左右起，晶体管尺寸微缩已不再自动带来单位功耗的降低。每次架构升级必须在相同的物理尺寸内塞进更多计算单元，同时维持或提升时钟频率，结果就是TDP的刚性增长。</p><p>B200单芯片集成2080亿晶体管（双die设计，10TB/s NV-HBI互联），比H100的800亿晶体管翻了2.6倍。Rubin R100的晶体管规模进一步提升，同时引入HBM4（288GB/GPU，22TB/s带宽——H100的6.6倍）。</p><p>每一次计算密度的跃迁，都对应着功耗密度的跃迁。这不是工程优化的失败——这是半导体物理的边界条件。</p><h3 id="_2-3-非gpu功耗的叠加效应" tabindex="-1">2.3 非GPU功耗的叠加效应 <a class="header-anchor" href="#_2-3-非gpu功耗的叠加效应" aria-label="Permalink to &quot;2.3 非GPU功耗的叠加效应&quot;">​</a></h3><p>以DGX H100为例：8颗GPU的TDP合计5,600W，整台服务器功耗10,200W——45%来自非GPU组件（CPU、内存、NVSwitch、电源转换、风扇）。</p><p>到了GB200 NVL72（72×B200 + 36×Grace CPU），整机柜120-130kW，GPU占比约60%，剩余40%仍然是非GPU开销。</p><p>这意味着：即使GPU能效在未来翻倍，系统总功耗的下降幅度也要打6折——因为那40%的非GPU功耗不会同步下降。</p><hr><h2 id="三、散热级-从空气到液体的代际切换" tabindex="-1">三、散热级：从空气到液体的代际切换 <a class="header-anchor" href="#三、散热级-从空气到液体的代际切换" aria-label="Permalink to &quot;三、散热级：从空气到液体的代际切换&quot;">​</a></h2><h3 id="_3-1-风冷的天花板" tabindex="-1">3.1 风冷的天花板 <a class="header-anchor" href="#_3-1-风冷的天花板" aria-label="Permalink to &quot;3.1 风冷的天花板&quot;">​</a></h3><p>传统风冷数据中心设计标准：5-15kW/柜。H100时代（30-40kW/柜）：风冷已接近极限（热通道封闭、高风量、高噪）。B200时代（120-130kW/柜）：风冷物理失效。</p><p><strong>临界点：约40kW/柜</strong>——超过此阈值，空气的比热容和导热系数已不足以维持GPU在安全温度范围内的持续满负荷运行。</p><p>Adam Silva Consulting实测：在50kW/柜密度下，冷却系统故障后GPU温度从22°C上升到临界失效阈值只需<strong>不到75秒</strong>。这个密度下不存在&quot;优雅降级&quot;——要么双冗余液冷环路，要么宕机。</p><p>DVFS（动态电压频率缩放）在GPU逼近热极限时启动，计算吞吐量可下降<strong>17%以上</strong>。对于训练一个成本数千万美元的大模型，17%的吞吐损失意味着训练周期拉长、GPU利用率坍塌。</p><h3 id="_3-2-rubin的散热约束" tabindex="-1">3.2 Rubin的散热约束 <a class="header-anchor" href="#_3-2-rubin的散热约束" aria-label="Permalink to &quot;3.2 Rubin的散热约束&quot;">​</a></h3><p>Rubin NVL72官方设计约束：</p><ul><li><strong>必须100%液冷</strong>（非&quot;推荐&quot;——硬性设计约束）</li><li>进水温度45°C（减少压缩机功耗，降低PUE）</li><li>全新MGX（Oberon）机架设计，全线缆直连、无风扇托盘</li><li>单个Rubin NVL72机柜重约4,000磅（约1.8吨——相当于一辆皮卡）</li></ul><p>Kyber NVL576（600kW/柜）同样强制液冷。两相液冷（利用介电液体的液→气相变潜热）正在成为超300kW/柜场景的主流方案——相比单相液冷，冷却液流量只需约<strong>五分之一</strong>。</p><h3 id="_3-3-资产搁浅风险" tabindex="-1">3.3 资产搁浅风险 <a class="header-anchor" href="#_3-3-资产搁浅风险" aria-label="Permalink to &quot;3.3 资产搁浅风险&quot;">​</a></h3><p>行业分析师Tony Grayson提出&quot;十亿美元混凝土空壳&quot;（billion-dollar concrete husks）：为某一代功率密度建造的数据中心厂房，在下一代设备面前完全失效。</p><p><strong>具体数据：</strong></p><ul><li>2024年建的120kW风冷数据中心 → 2027年装不了600kW Kyber机柜</li><li>风冷→液冷改造成本：约<strong>每兆瓦200-300万美元</strong></li><li>10MW数据中心改造费用：2,000-3,000万美元（假设结构可改）</li></ul><p>Uptime Institute观察：运营商现在设计时必须留出极大余量，因为&quot;电力热容量搁浅&quot;的风险已超过&quot;空间空置&quot;的风险。建太多比建太少更安全。</p><p>散热密度超过80-100kW/柜时，&quot;能不能散热&quot;已经取代&quot;有没有电&quot;成为选址的第一决定因素。</p><p>Dell&#39;Oro预测：到2028年全球数据中心液冷市场将接近<strong>200亿美元</strong>。</p><hr><h2 id="四、配电级-从48v到800v-从充裕到短缺" tabindex="-1">四、配电级：从48V到800V，从充裕到短缺 <a class="header-anchor" href="#四、配电级-从48v到800v-从充裕到短缺" aria-label="Permalink to &quot;四、配电级：从48V到800V，从充裕到短缺&quot;">​</a></h2><h3 id="_4-1-800v-hvdc架构替换" tabindex="-1">4.1 800V HVDC架构替换 <a class="header-anchor" href="#_4-1-800v-hvdc架构替换" aria-label="Permalink to &quot;4.1 800V HVDC架构替换&quot;">​</a></h3><p>GPU供电架构演进：</p><table tabindex="0"><thead><tr><th style="text-align:center;">阶段</th><th style="text-align:center;">时间</th><th style="text-align:center;">供电架构</th><th style="text-align:center;">ASP影响</th></tr></thead><tbody><tr><td style="text-align:center;">传统</td><td style="text-align:center;">至2024</td><td style="text-align:center;">48V机架级UPS+PDU</td><td style="text-align:center;">基准</td></tr><tr><td style="text-align:center;">过渡</td><td style="text-align:center;">2026-27</td><td style="text-align:center;">行级800V HVDC侧柜</td><td style="text-align:center;">单柜~50万美元，比传统高10倍</td></tr><tr><td style="text-align:center;">原生</td><td style="text-align:center;">2027-28</td><td style="text-align:center;">800V原生芯片组，UPS退出核心回路</td><td style="text-align:center;">BBU毛利率最高</td></tr><tr><td style="text-align:center;">固态</td><td style="text-align:center;">2028+</td><td style="text-align:center;">固态变压器取代低压变压器+整流器</td><td style="text-align:center;">效率82%→87%，体积缩减14倍</td></tr></tbody></table><p>英伟达2025年10月发布800V HVDC白皮书，推动数据中心配电从交流向直流转型。</p><p><strong>物理原理：</strong> P = I²R。电压翻倍，同功率下电流减半，线路损耗降至1/4。600kW Kyber机柜在415V交流下的铜材已不可接受，800V直流下同截面线缆可输送1.5倍以上功率。</p><p><strong>生态系统：</strong> Vertiv、Schneider Electric、ABB、Siemens、Delta等约20家合作伙伴正在开发800V DC产品线。SemiAnalysis预测2030年约<strong>39GW</strong> AI数据中心采用800V HVDC。</p><p><strong>投资含义：</strong> 壁垒最高的是两端——底层功率半导体（SiC）和整机系统集成（SST/HVDC）；放量最早的是上游电源模块。</p><h3 id="_4-2-变压器-全链路最短的木板" tabindex="-1">4.2 变压器：全链路最短的木板 <a class="header-anchor" href="#_4-2-变压器-全链路最短的木板" aria-label="Permalink to &quot;4.2 变压器：全链路最短的木板&quot;">​</a></h3><p>数据中心外部——从区域电网110kV/220kV到内部10kV/35kV——必须经过大型电力变压器。这个不起眼的设备已经成为全链路中最紧的瓶颈。</p><p><strong>花旗银行全球高压变压器供需测算：</strong></p><table tabindex="0"><thead><tr><th style="text-align:center;">年份</th><th style="text-align:center;">年度供给缺口</th><th style="text-align:center;">累积短缺</th></tr></thead><tbody><tr><td style="text-align:center;">2025</td><td style="text-align:center;">~30%（708 GVA）</td><td style="text-align:center;">708 GVA</td></tr><tr><td style="text-align:center;">2026</td><td style="text-align:center;">~22%（522 GVA）</td><td style="text-align:center;">1,230 GVA</td></tr><tr><td style="text-align:center;">2027</td><td style="text-align:center;">~13%（325 GVA）</td><td style="text-align:center;">1,555 GVA</td></tr><tr><td style="text-align:center;">2028</td><td style="text-align:center;">~5%（144 GVA）</td><td style="text-align:center;"><strong>1,699 GVA（峰值）</strong></td></tr></tbody></table><p><strong>交付周期变化：</strong></p><table tabindex="0"><thead><tr><th style="text-align:center;">时间</th><th style="text-align:center;">大型变压器典型交付周期</th></tr></thead><tbody><tr><td style="text-align:center;">2020年前</td><td style="text-align:center;">24-30个月</td></tr><tr><td style="text-align:center;">2021</td><td style="text-align:center;">~50周</td></tr><tr><td style="text-align:center;">2025</td><td style="text-align:center;">100-127周</td></tr><tr><td style="text-align:center;">2026</td><td style="text-align:center;"><strong>160周以上</strong>（部分项目翻新退役电厂二手设备）</td></tr></tbody></table><p>GE Vernova电气化部门CEO：过去数据中心规模小、交期可接受；如今AI企业希望在18个月内拿到设备，但现在需要160周——差了近10倍。</p><p><strong>Sightline Climate 2026年报告的核心发现：</strong> 美国2026年规划的新增数据中心容量约12GW，其中<strong>只有约1GW的设备订单已经锁定</strong>（变压器、开关柜、电池）。剩余11GW停留在纸面上。</p><p><strong>中国变压器的结构性机遇：</strong></p><ul><li>2025年变压器出口总值646亿元，+36.3%</li><li>2026年1-2月+41.4%，景气延续第26个月</li><li>对美出口暴增182%</li><li>出口均价同比上涨6-30.5%</li><li>全球60%产能在中国，交付周期3-6月 vs 欧美18月+ — 结构性替代</li></ul><hr><h2 id="五、电网级-排队5到10年的并网危机" tabindex="-1">五、电网级：排队5到10年的并网危机 <a class="header-anchor" href="#五、电网级-排队5到10年的并网危机" aria-label="Permalink to &quot;五、电网级：排队5到10年的并网危机&quot;">​</a></h2><h3 id="_5-1-pjm-5年以上的等待" tabindex="-1">5.1 PJM：5年以上的等待 <a class="header-anchor" href="#_5-1-pjm-5年以上的等待" aria-label="Permalink to &quot;5.1 PJM：5年以上的等待&quot;">​</a></h3><p>PJM官方承认：数据中心并网申请需等待<strong>5年以上</strong>才能获得接入审批。数据中心建设周期18-24个月。合计：从提交申请到通电，总周期可能超过<strong>7年</strong>。</p><p>PJM明确警告存在<strong>6.5GW以上容量缺口</strong>。</p><h3 id="_5-2-ercot-250-000mw的井喷" tabindex="-1">5.2 ERCOT：250,000MW的井喷 <a class="header-anchor" href="#_5-2-ercot-250-000mw的井喷" aria-label="Permalink to &quot;5.2 ERCOT：250,000MW的井喷&quot;">​</a></h3><p>ERCOT预测2032年峰值负荷：<strong>367GW</strong>（2023年实际峰值85GW）。</p><p>ERCOT原有系统仅设计处理40-50个大型负荷项目。2025年一年收到<strong>225个新申请</strong>——约70%是数据中心。排队中的大型负荷项目申报容量超过<strong>250,000MW</strong>——已达德州历史峰值3倍。</p><p>ERCOT CEO Pablo Vegas（2026年6月会议）：&quot;我们有可能解决一个全国性的问题——如何以可靠、稳定、兼顾经济增长的方式处理这些并网需求。&quot;</p><p>ERCOT应对方案：<strong>批次处理</strong>（Batch Processing）——把数据中心项目分组打包做影响研究。2026年6月2日通过首批&quot;Batch Zero&quot;，但完整框架要到2027年。</p><h3 id="_5-3-ferc的介入" tabindex="-1">5.3 FERC的介入 <a class="header-anchor" href="#_5-3-ferc的介入" aria-label="Permalink to &quot;5.3 FERC的介入&quot;">​</a></h3><p>2026年6月18日，FERC要求全美六大区域电网运营商：</p><ol><li><strong>30天内</strong>提交资源充足性报告</li><li>重新审查大规模负荷接入规则</li></ol><p>五个改革领域：成本分摊、共址发电、灵活负荷输电服务、负荷侧发电评估、互联队列透明化。</p><p>信号很明确：电网追不上数据中心增速，监管必须主动介入。</p><h3 id="_5-4-互联队列的损耗率" tabindex="-1">5.4 互联队列的损耗率 <a class="header-anchor" href="#_5-4-互联队列的损耗率" aria-label="Permalink to &quot;5.4 互联队列的损耗率&quot;">​</a></h3><p>ERCOT和PJM合计1,216个活跃互联项目在排队（111.6GW发电+64.3GW储能）。</p><p>互联申请的实际转化率很低：2000-2019年提交互联申请的容量中，到2024年底只有<strong>13%</strong> 进入商业运营，10%活跃在建，<strong>77%已撤回</strong>。</p><p>大部分容量在漫长的审批过程中因为各种原因（成本超预算、技术条件变化、开发商退出）选择了退出。</p><hr><h2 id="六、哪里先断-瓶颈优先级排序" tabindex="-1">六、哪里先断？瓶颈优先级排序 <a class="header-anchor" href="#六、哪里先断-瓶颈优先级排序" aria-label="Permalink to &quot;六、哪里先断？瓶颈优先级排序&quot;">​</a></h2><h3 id="🥇-第一-变压器-2026-2028峰值缺口1-699gva" tabindex="-1">🥇 第一：变压器（2026-2028峰值缺口1,699GVA） <a class="header-anchor" href="#🥇-第一-变压器-2026-2028峰值缺口1-699gva" aria-label="Permalink to &quot;🥇 第一：变压器（2026-2028峰值缺口1,699GVA）&quot;">​</a></h3><ul><li>全链路中几乎没有替代方案的环节（其他环节都有备选路径）</li><li>交付周期160周，是AI开发周期（12-18月）的3-4倍</li><li>扩产受制于硅钢片、铜线、绝缘材料、大型绕线设备等供应链约束，周期3-5年</li><li>Sightline的11/12比例最具说服力</li></ul><h3 id="🥈-第二-区域电网并网-5-10年周期" tabindex="-1">🥈 第二：区域电网并网（5-10年周期） <a class="header-anchor" href="#🥈-第二-区域电网并网-5-10年周期" aria-label="Permalink to &quot;🥈 第二：区域电网并网（5-10年周期）&quot;">​</a></h3><ul><li>FERC介入后可能加速，但监管重审本身需要1-2年</li><li>ERCOT Batch Zero的完整框架要到2027年</li><li>互联队列77%的退出率说明不确定性极高</li><li>解决方案：表后发电、共址核能正在从&quot;备选&quot;变&quot;首选&quot;</li></ul><h3 id="🥉-第三-液冷存量搁浅-2027-2028灰犀牛" tabindex="-1">🥉 第三：液冷存量搁浅（2027-2028灰犀牛） <a class="header-anchor" href="#🥉-第三-液冷存量搁浅-2027-2028灰犀牛" aria-label="Permalink to &quot;🥉 第三：液冷存量搁浅（2027-2028灰犀牛）&quot;">​</a></h3><ul><li>现有风冷数据中心无法直接升级到Rubin/Kyber级别</li><li>新建液冷数据中心周期24-36个月，需在2026年开始审批</li><li>Dell&#39;Oro预测液冷市场2028年~200亿美元</li><li>两相液冷、冷板CDU、冷却液分配单元是中国供应链的核心机会</li></ul><p><strong>芯片供应：约束最小</strong>。HBM4初期或有瓶颈，12-18个月内可缓解。相比电力链的约束，芯片是最快能解决的问题。</p><hr><h2 id="七、投资含义-三条监测指标" tabindex="-1">七、投资含义：三条监测指标 <a class="header-anchor" href="#七、投资含义-三条监测指标" aria-label="Permalink to &quot;七、投资含义：三条监测指标&quot;">​</a></h2><p><strong>指标一：变压器交付周期。</strong> 160周是峰值还是起点？决定供给瓶颈是否深化。</p><p><strong>指标二：液冷数据中心的增量供给 vs Kyber出货时间线。</strong> 如果液冷产能跟不上，2027-2028年将出现&quot;有GPU没地方装&quot;。</p><p><strong>指标三：FERC规则重审和ERCOT Batch进度。</strong> 监管信号直接决定新项目的时间线和成本结构。</p><h3 id="三个方向" tabindex="-1">三个方向 <a class="header-anchor" href="#三个方向" aria-label="Permalink to &quot;三个方向&quot;">​</a></h3><ol><li><strong>变压器和电力设备出口</strong>：确定性最高，3年内高速增长可预见</li><li><strong>液冷基础设施</strong>：代际切换，新建优先于改造</li><li><strong>表后电/分布式能源</strong>：SOFC、小型燃机、共址储能——&quot;等不起电网&quot;带来的VC级机会</li></ol><hr><h2 id="八、风险提示" tabindex="-1">八、风险提示 <a class="header-anchor" href="#八、风险提示" aria-label="Permalink to &quot;八、风险提示&quot;">​</a></h2><ol><li><strong>AI算力需求修正</strong>：若Scaling Law增速放缓或模型效率大幅提升，全链路的需求假设可能被下调</li><li><strong>电力设备扩产慢于预期</strong>：变压器的硅钢片、铜线供应可能持续紧张</li><li><strong>液冷技术路线不确定性</strong>：单相vs两相、冷板vs浸没，不同技术路线选择的投入回报存在差异</li><li><strong>监管政策变化</strong>：FERC规则重审、各州数据中心税收和电力政策可能影响项目落地速度</li><li><strong>HBM4供应风险</strong>：SK海力士量产进度和良率可能影响Rubin初期出货量</li></ol><hr><p><em>数据来源：NVIDIA GTC 2026、Epoch AI数据中心功耗建模、American Compute power budget、ARC Compute、ModulEdge Rubin影响分析、花旗银行变压器供需2026、Sightline Climate 2026.04、ERCOT/FERC/SB6公开文件、Uptime Institute、Dell&#39;Oro液冷预测、SemiAnalysis 800V HVDC、Adam Silva Consulting散热实测、Wood Mackenzie</em></p><p><em>本文为投资研究框架分享，不构成任何投资建议。数据截止2026年6月。</em></p>',101)])])}const x=e(n,[["render",i]]);export{p as __pageData,x as default};
